mapper.select:

select s.id, s.settlement_no, s.order_id, o.order_no, s.user_id, u.real_name as user_name,
s.instrument_id, i.instrument_name, o.department_id, d.dept_name as department_name,
s.bill_type, s.estimated_amount, s.discount_amount, s.final_amount, s.settle_status,
s.create_time, s.settled_time, s.operator_user_id, op.real_name as operator_name,
o.order_status, o.pay_status, o.settlement_status
from biz_settlement_record s
left join biz_reservation_order o on o.id = s.order_id
left join sys_user u on u.id = s.user_id
left join biz_instrument i on i.id = s.instrument_id
left join sys_department d on d.id = o.department_id
left join sys_user op on op.id = s.operator_user_id
where 1=1
and s.settle_status = #{status}
and o.department_id = #{departmentId}
and s.order_id = #{orderId}

  and (s.settlement_no like concat('%', #{keyword}, '%')
  or o.order_no like concat('%', #{keyword}, '%')
  or u.real_name like concat('%', #{keyword}, '%')
  or i.instrument_name like concat('%', #{keyword}, '%'))

and s.create_time >= #{createStart}
and s.create_time <= #{createEnd}
and s.settled_time >= #{settledStart}
and s.settled_time <= #{settledEnd}
and o.department_id = #{scopeDepartmentId}
order by s.create_time desc
limit #{offset}, #{pageSize}


select count(1)
from biz_settlement_record s
left join biz_reservation_order o on o.id = s.order_id
left join sys_user u on u.id = s.user_id
left join biz_instrument i on i.id = s.instrument_id
where 1=1
and s.settle_status = #{status}
and o.department_id = #{departmentId}
and s.order_id = #{orderId}

  and (s.settlement_no like concat('%', #{keyword}, '%')
  or o.order_no like concat('%', #{keyword}, '%')
  or u.real_name like concat('%', #{keyword}, '%')
  or i.instrument_name like concat('%', #{keyword}, '%'))

and s.create_time >= #{createStart}
and s.create_time <= #{createEnd}
and s.settled_time >= #{settledStart}
and s.settled_time <= #{settledEnd}
and o.department_id = #{scopeDepartmentId}
